           group_id, plan, (cycles_elapsed+1) AS next_cycle,
           COUNT(*) n, SUM(seat_count) seats, SUM(effective_price*seat_count) current_eff_mrr, AVG(promotion) avg_promo, AVG(effective_price) avg_eff,
           MIN(start_day) min_start, MAX(start_day) max_start
    FROM active
    WHERE due_day BETWEEN 344 AND 357
    GROUP BY due_day, group_id, plan, next_cycle
    ORDER BY due_day, group_id, plan, next_cycle
    LIMIT 2000
    """)['rows']
